<?php
namespace App\Models;
use App\Enums\RecoveryStatus;use App\Models\Concerns\BelongsToTenant;use App\Models\Concerns\HasAuditTrail;use Illuminate\Database\Eloquent\Concerns\HasUlids;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\Relations\HasMany;
class LoanRecoveryCase extends Model{use BelongsToTenant,HasAuditTrail,HasUlids;protected $fillable=['cooperative_id','loan_id','member_id','reference','status','days_past_due','arrears_minor','assigned_to','promise_date','promise_amount_minor','opened_at','resolved_at'];protected function casts():array{return ['status'=>RecoveryStatus::class,'days_past_due'=>'integer','arrears_minor'=>'integer','promise_date'=>'date','promise_amount_minor'=>'integer','opened_at'=>'datetime','resolved_at'=>'datetime'];}public function loan():\Illuminate\Database\Eloquent\Relations\BelongsTo{return $this->belongsTo(Loan::class);}public function actions():HasMany{return $this->hasMany(LoanRecoveryAction::class);}}
